import clsx from 'clsx';
import { useRef, type MutableRefObject } from 'react';

import { Tooltip } from '../../../../../../../overlays/tooltip/Tooltip.js';
import { DEFAULT_TRUNCATION_MODE } from '../../../../../constants.js';
import { useChartLayoutRatio } from '../../../../chart-layout/hooks/useChartLayoutRatio.js';
import { charsFontWidth12pixelsSize500Map } from '../../../../text-ellipsis/chars-font-width-map.js';
import { ChartTextEllipsis } from '../../../../text-ellipsis/ChartTextEllipsis.js';
import { calculateWidth } from '../../../../text-ellipsis/truncate-string.js';
import { LABEL_ITEM_CLASSNAME } from '../../constants.js';
import { useLegendGridSettings } from '../../context/LegendGridSettingsContext.js';
import { useLegend } from '../../hooks/useLegend.js';
import { LegendItem } from '../../types/legend.js';
import {
  baseLegendButton,
  legendNameButton,
  legendNameButtonOverride,
} from '../ChartLegendItem/ChartLegendItem.sty.js';

export interface ChartLegendItemLabelProps {
  item: LegendItem;
  buttonRef: MutableRefObject<HTMLButtonElement | null>;
  visible: boolean;
  onButtonClick: (event: MouseEvent) => void;
  onButtonKeydown: (event: KeyboardEvent) => void;
  onMouseEnter: () => void;
  onMouseLeave: () => void;
}

const MAX_WIDTH_GAP = 15;

export const ChartLegendItemLabel = (props: ChartLegendItemLabelProps) => {
  const {
    item,
    buttonRef,
    visible,
    onButtonKeydown,
    onButtonClick,
    onMouseEnter,
    onMouseLeave,
  } = props;
  const { name } = item;

  const textRef = useRef<HTMLSpanElement>(null);

  const { readyForAutoRatio, ratio } = useChartLayoutRatio();
  const { interactionsDisabled, truncationMode } = useLegend();
  const { maxItemWidth } = useLegendGridSettings();

  let applyTruncation = false;
  if (buttonRef.current) {
    const textWidth = calculateWidth(
      item.name,
      charsFontWidth12pixelsSize500Map,
    );
    const availableWidth = buttonRef.current.clientWidth;
    applyTruncation = textWidth >= availableWidth;
  }

  return (
    <Tooltip text={name} disabled={!applyTruncation}>
      <button
        data-testid="chart-legend-item-name"
        data-dt-children-name="LegendIsolateItem"
        ref={buttonRef}
        onClick={(evt) => onButtonClick(evt.nativeEvent)}
        onKeyDown={(evt) => onButtonKeydown(evt.nativeEvent)}
        onMouseEnter={onMouseEnter}
        onMouseLeave={onMouseLeave}
        tabIndex={interactionsDisabled ? -1 : 0}
        className={clsx(
          baseLegendButton,
          legendNameButtonOverride,
          legendNameButton({
            isInteractive: !interactionsDisabled,
            isSubdued: !visible,
          }),
        )}
        style={{
          flexBasis: maxItemWidth + MAX_WIDTH_GAP,
        }}
      >
        {ratio !== 'auto' || readyForAutoRatio ? (
          <ChartTextEllipsis
            truncationMode={truncationMode ?? DEFAULT_TRUNCATION_MODE}
            aria-label="Series name"
            ref={textRef}
            charsFontWidthMap={charsFontWidth12pixelsSize500Map}
          >
            {item.name}
          </ChartTextEllipsis>
        ) : (
          <span className={LABEL_ITEM_CLASSNAME}>{item.name}</span>
        )}
      </button>
    </Tooltip>
  );
};
